{
  "business_expectations": [
    {
      "expectation_id": "性别条件正确解析为女性",
      "description": "用户意图筛选女性客户，期望条件包含 clientSex MATCH '女'",
      "expected_outcome": "conditions 中包含字段 clientSex，操作符 MATCH，值为 '女'",
      "acceptance_criteria": "conditions 数组中存在 field='clientSex', operator='MATCH', value='女' 的条件",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "年龄条件正确解析为25岁及以上",
      "description": "用户意图 '25岁以上'，包含边界，期望条件为 clientAge GTE 25",
      "expected_outcome": "conditions 中包含字段 clientAge，操作符 GTE，值为 25",
      "acceptance_criteria": "conditions 数组中存在 field='clientAge', operator='GTE', value=25 的条件",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "年缴保费条件正确解析为大于1万元",
      "description": "用户意图 '年缴保费大于1万'，单位元，1万=10000，大于不含等于",
      "expected_outcome": "conditions 中包含字段 annPremSegNum，操作符 GT，值为 10000",
      "acceptance_criteria": "conditions 数组中存在 field='annPremSegNum', operator='GT', value=10000 的条件",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "条件逻辑为AND",
      "description": "多个条件需要同时满足，无 OR 关系",
      "expected_outcome": "query_logic 应为 'AND'，所有条件组合正确",
      "acceptance_criteria": "query_logic 字段值为 'AND' 或 conditions 数组表达的逻辑为 AND",
      "blocking_level": "blocking"
    }
  ],
  "expected": {
    "code": 200,
    "msg": "成功",
    "query": "25岁以上的女性客户，年缴保费大于1万",
    "conditions": [
      {
        "field": "clientSex",
        "operator": "MATCH",
        "value": "女"
      },
      {
        "field": "clientAge",
        "operator": "GTE",
        "value": 25
      },
      {
        "field": "annPremSegNum",
        "operator": "GT",
        "value": 10000
      }
    ],
    "robot_text": null,
    "end_flag": null,
    "trace_id": null,
    "query_logic": "AND",
    "matched_level": null,
    "matched_patterns": null,
    "rewritten_query": null,
    "intent_summary": null,
    "confidence": null,
    "cost_times": null
  },
  "reconstructed_intent": "用户希望查询年龄在25岁及以上、性别为女性的客户，且其年缴保费大于1万元。",
  "judge_basis": "根据 capability_manifest 中 clientAge 字段的注释：'30岁以上→GTE 30岁'，因此 '25岁以上' 应解析为 GTE 25；clientSex 字段的枚举值映射 '女性'->'女'；annPremSegNum 字段支持 GT 操作符，单位元，1万=10000，'大于' 对应 GT。所有条件为且关系。",
  "reference_generation_basis": {
    "fields_used": ["clientSex", "clientAge", "annPremSegNum"],
    "value_mappings": {
      "sex": "女性 -> 女",
      "premium_unit": "1万 -> 10000"
    },
    "enhanced_rules_applied": ["年龄-及以上规则将 '25岁以上' 转为 GTE 25"],
    "notes": "年龄字段仅支持 GTE，含边界；年缴保费字段仅支持大于关系，不含等于"
  }
}

